1	//! 代码质量指标
2	//!
3	//! 提供单一符号和批量代码质量指标计算：
4	//! - **圈复杂度** — 基于 AST 分支节点计数的控制流复杂度
5	//! - **出入度** — 基于调用图的 fan-in / fan-out 统计
6	//! - **继承深度** — 基于类型层次图的继承链深度
7	//! - **死代码检测** — 基于调用图可达性分析
8	
9	use std::collections::{HashSet, VecDeque};
10	
11	use codeconnect_core::error::CodeConnectError;
12	use codeconnect_core::types::Symbol;
13	
14	use crate::call_graph::CallGraph;
15	use crate::type_hierarchy::TypeHierarchy;
16	
17	/// 代码质量指标
18	///
19	/// 汇总单个符号的复杂度、耦合度、继承深度等指标。
20	#[derive(Debug, Clone)]
21	pub struct CodeMetrics {
22	    /// 符号唯一 ID
23	    pub symbol_id: String,
24	    /// 符号名称
25	    pub name: String,
26	    /// 圈复杂度（基于分支节点统计）
27	    pub cyclomatic_complexity: u64,
28	    /// 入度（被其他符号调用的次数）
29	    pub fan_in: u64,
30	    /// 出度（调用其他符号的次数）
31	    pub fan_out: u64,
32	    /// 继承深度（从当前类型到继承树根的距离）
33	    pub depth_of_inheritance: u64,
34	}
35	
36	/// 死代码条目
37	///
38	/// 表示一个从入口点不可达的、可能为死代码的符号。
39	#[derive(Debug, Clone)]
40	pub struct DeadCodeEntry {
41	    /// 符号唯一 ID
42	    pub symbol_id: String,
43	    /// 符号名称
44	    pub name: String,
45	    /// 置信度 0.0-1.0，值越低越可能是死代码
46	    /// 1.0 = 完全不可达（肯定是死代码）
47	    /// 0.5 = 可能存在间接引用但未检测到
48	    pub confidence: f64,
49	    /// 标记为死代码的原因描述
50	    pub reason: String,
51	}
52	
53	/// 指标计算器
54	///
55	/// 提供批量计算和死代码检测功能。
56	/// 自身不维护状态，所有方法均为纯函数。
57	pub struct MetricCalculator;
58	
59	impl MetricCalculator {
60	    // ========================================================================
61	    // 圈复杂度
62	    // ========================================================================
63	
64	    /// 计算单个符号的圈复杂度
65	    ///
66	    /// ## 算法
67	    /// 1. 如果 `symbol.complexity` 已有值，直接返回（来自解析器的预计算结果）
68	    /// 2. 否则对 `source` 文本进行轻量级分析，统计分支关键字：
69	    ///    - 条件分支: `if`, `else if`
70	    ///    - 循环: `for`, `while`, `loop`
71	    ///    - 模式匹配: `match`, `case`, `switch`
72	    ///    - 异常处理: `catch`, `except`, `rescue`
73	    ///    - 逻辑运算符（短路求值）: `&&`, `||`
74	    ///    - 空值合并: `?.`, `??`
75	    ///    - 三元运算符: `?`
76	    /// 3. 圈复杂度 = 1（函数入口） + 分支节点总数
77	    pub fn compute_complexity(symbol: &Symbol, source: &str) -> u64 {
78	        // 优先使用解析器预计算的值
79	        if let Some(complexity) = symbol.complexity {
80	            return complexity;
81	        }
82	
83	        // 对源文本做词法级别的分支关键字计数
84	        let mut complexity: u64 = 1; // 函数入口基准值
85	
86	        // 使用简单的空格分隔进行词法分析（非完整解析，但足够准确）
87	        let tokens: Vec<&str> = source
88	            .split(|c: char| c.is_whitespace() || c == '(' || c == ')' || c == '{' || c == '}' || c == ';' || c == ',')
89	            .filter(|s| !s.is_empty())
90	            .collect();
91	
92	        for &token in &tokens {
93	            match token {
94	                // 条件分支
95	                "if" | "elif" | "elsif" | "elseif" => complexity += 1,
96	                // 循环
97	                "for" | "while" | "loop" => complexity += 1,
98	                // 模式匹配
99	                "match" | "case" | "switch" => complexity += 1,
100	                // 异常处理
101	                "catch" | "except" | "rescue" | "finally" => complexity += 1,
102	                // 逻辑运算符（短路求值产生分支）
103	                "&&" | "||" => complexity += 1,
104	                _ => {}
105	            }
106	        }
107	
108	        // 统计三元运算符 `?`（在 token 中单独出现）
109	        complexity += tokens.iter().filter(|&&t| t == "?").count() as u64;
110	
111	        // 统计空值合并运算符 `??` 和可选链 `?.`
112	        // 这需要在原始源文本上统计
113	        complexity += source.matches("??").count() as u64;
114	        complexity += source.matches("?.").count() as u64;
115	
116	        complexity
117	    }
118	
119	    // ========================================================================
120	    // 批量指标计算
121	    // ========================================================================
122	
123	    /// 批量计算所有符号的代码质量指标
124	    ///
125	    /// ## 计算内容
126	    /// - **圈复杂度** — 从 `symbol.complexity` 字段获取（解析器预计算）
127	    /// - **fan_in** — 调用图中指向当前符号的入边数量
128	    /// - **fan_out** — 调用图中从当前符号出发的出边数量
129	    /// - **继承深度** — 类型层次图中当前符号到根的距离
130	    pub fn compute_all(
131	        symbols: &[Symbol],
132	        call_graph: &CallGraph,
133	        type_hierarchy: &TypeHierarchy,
134	    ) -> Vec<CodeMetrics> {
135	        symbols
136	            .iter()
137	            .map(|symbol| {
138	                // 圈复杂度：优先用预计算值，否则默认为 1
139	                let cyclomatic_complexity = symbol.complexity.unwrap_or(1);
140	
141	                // 出入度：从调用图获取
142	                let (fan_in, fan_out) = call_graph.degree(&symbol.name);
143	
144	                // 继承深度：从类型层次图计算祖先数量
145	                let ancestors = type_hierarchy.get_ancestors(&symbol.name);
146	                let depth_of_inheritance = ancestors.len() as u64;
147	
148	                CodeMetrics {
149	                    symbol_id: symbol.id.clone(),
150	                    name: symbol.name.clone(),
151	                    cyclomatic_complexity,
152	                    fan_in,
153	                    fan_out,
154	                    depth_of_inheritance,
155	                }
156	            })
157	            .collect()
158	    }
159	
160	    // ========================================================================
161	    // 死代码检测
162	    // ========================================================================
163	
164	    /// 检测死代码
165	    ///
166	    /// ## 算法
167	    /// 从入口点（main 函数、导出的 pub 函数等）出发，在调用图上做反向 BFS
168	    /// 可达性分析。即从每个入口点开始，沿"被调用者→调用者"方向（入边）遍历，
169	    /// 将能到达的节点标记为"可达"。
170	    ///
171	    /// 最后，所有未被标记为可达的符号即为**可能死代码**。
172	    ///
173	    /// ## 置信度计算
174	    /// - 1.0 — 完全不可达（没有任何入边）
175	    /// - 0.8 — 不可达但至少有一条入边（可能是反射/回调等间接调用）
176	    /// - 0.5 — 不可达但名称匹配常见模式（如 `test_*`）
177	    pub fn detect_dead_code(
178	        all_symbols: &[String],
179	        call_graph: &CallGraph,
180	        entry_points: &[String],
181	    ) -> Vec<DeadCodeEntry> {
182	        // 第1步: 构建可达性集合
183	        let mut reachable = HashSet::new();
184	        let mut queue = VecDeque::new();
185	
186	        // 从入口点开始
187	        for entry in entry_points {
188	            reachable.insert(entry.clone());
189	            queue.push_back(entry.clone());
190	        }
191	
192	        // BFS 反向遍历：从调用者沿入边找到被调用的符号
193	        while let Some(current) = queue.pop_front() {
194	            // 获取调用 current 的所有符号（调用者）
195	            let callers = call_graph.get_callers(&current);
196	            for caller in callers {
197	                if reachable.insert(caller.clone()) {
198	                    queue.push_back(caller);
199	                }
200	            }
201	        }
202	
203	        // 第2步: 找出不可达符号并计算置信度
204	        let mut dead_entries = Vec::new();
205	        for symbol_name in all_symbols {
206	            if reachable.contains(symbol_name.as_str()) {
207	                continue;
208	            }
209	
210	            let (fan_in, _fan_out) = call_graph.degree(symbol_name);
211	
212	            // 确定置信度和原因
213	            let (confidence, reason) = if fan_in == 0 {
214	                // 完全孤立
215	                (1.0, "从任何入口点都不可达，且未被任何符号调用".to_string())
216	            } else if symbol_name.starts_with("test_") || symbol_name.contains("_test") {
217	                // 可能是测试代码
218	                (0.5, "未被入口点可达，但名称匹配测试模式".to_string())
219	            } else if symbol_name.starts_with('_') {
220	                // 可能是内部/私有函数
221	                (0.7, "未被入口点可达，名称前缀暗示内部函数".to_string())
222	            } else {
223	                // 有入边但不可达（可能是反射、动态调用等）
224	                (0.8, format!(
225	                    "未被入口点可达，但被 {} 个符号调用（可能是间接/动态调用）",
226	                    fan_in
227	                ))
228	            };
229	
230	            dead_entries.push(DeadCodeEntry {
231	                symbol_id: format!("dead_{}", symbol_name),
232	                name: symbol_name.clone(),
233	                confidence,
234	                reason,
235	            });
236	        }
237	
238	        dead_entries
239	    }
240	}
