255	        Symbol {
256	            id: id.to_string(),
257	            name: name.to_string(),
258	            kind: SymbolKind::Function,
259	            location: SourceLocation {
260	                file_path: "test.rs".to_string(),
261	                line: 1,
262	                column: 1,
263	                end_line: 1,
264	                end_column: 1,
265	            },
266	            signature: None,
267	            doc_comment: None,
268	            parent_id: None,
269	            modifiers: vec![],
270	            is_exported: false,
271	            complexity,
272	        }
273	    }
