442	    #[test]
443	    fn test_compute_all_integration() {
444	        // 构建调用图
445	        let mut cg = CallGraph::new();
446	        cg.add_edge_raw("main", "helper");
447	        cg.add_edge_raw("main", "logger");
448	        cg.add_edge_raw("helper", "logger");
449	        cg.add_edge_raw("orphan", "logger");
450	
451	        // 构建类型层次
452	        let type_hierarchy = build_sample_hierarchy();
453	
454	        // 符号列表
455	        let symbols = vec![
456	            make_symbol("s1", "main", Some(3)),
457	            make_symbol("s2", "helper", Some(2)),
458	            make_symbol("s3", "logger", Some(1)),
459	            make_symbol("s4", "orphan", None), // 无预计算复杂度
460	            make_symbol("s5", "Dog", Some(5)),
461	        ];
462	
463	        let metrics = MetricCalculator::compute_all(&symbols, &cg, &type_hierarchy);
464	
465	        // 验证 main
466	        let main = metrics.iter().find(|m| m.name == "main").unwrap();
467	        assert_eq!(main.cyclomatic_complexity, 3);
468	        assert_eq!(main.fan_in, 0); // 没有被调用
469	        assert_eq!(main.fan_out, 2); // 调用了 helper 和 logger
470	        assert_eq!(main.depth_of_inheritance, 0); // 不在类型层次中
471	
472	        // 验证 helper
473	        let helper = metrics.iter().find(|m| m.name == "helper").unwrap();
474	        assert_eq!(helper.cyclomatic_complexity, 2);
475	        assert_eq!(helper.fan_in, 1); // 被 main 调用
476	        assert_eq!(helper.fan_out, 1); // 调用 logger
477	        assert_eq!(helper.depth_of_inheritance, 0);
478	
479	        // 验证 logger
480	        let logger = metrics.iter().find(|m| m.name == "logger").unwrap();
481	        assert_eq!(logger.cyclomatic_complexity, 1);
482	        assert_eq!(logger.fan_in, 3); // 被 main, helper, orphan 调用
483	        assert_eq!(logger.fan_out, 0);
484	        assert_eq!(logger.depth_of_inheritance, 0);
485	
486	        // 验证 orphan
487	        let orphan = metrics.iter().find(|m| m.name == "orphan").unwrap();
488	        assert_eq!(orphan.cyclomatic_complexity, 1); // 回退默认值
489	        assert_eq!(orphan.fan_in, 0);
490	        assert_eq!(orphan.fan_out, 1); // 调用 logger
491	
492	        // 验证 Dog（在类型层次中）
493	        let dog = metrics.iter().find(|m| m.name == "Dog").unwrap();
494	        assert_eq!(dog.cyclomatic_complexity, 5);
495	        assert_eq!(dog.fan_in, 0);
496	        assert_eq!(dog.fan_out, 0);
497	        assert_eq!(dog.depth_of_inheritance, 2); // Dog → Animal → Object
498	    }
