537	    #[test]
538	    fn test_detect_dead_code_partially_reachable() {
539	        let mut cg = CallGraph::new();
540	        cg.add_edge_raw("main", "helper");
541	        cg.add_edge_raw("main", "util");
542	        cg.add_edge_raw("orphan", "dead_func");
543	
544	        let all_symbols: Vec<String> = vec![
545	            "main".into(),
546	            "helper".into(),
547	            "util".into(),
548	            "orphan".into(),
549	            "dead_func".into(),
550	        ];
551	        let entry_points: Vec<String> = vec!["main".into()];
552	
553	        let dead = MetricCalculator::detect_dead_code(&all_symbols, &cg, &entry_points);
554	        // main, helper, util 可达
555	        // orphan 和 dead_func 不可达
556	        assert_eq!(dead.len(), 2);
557	
