1	//! 符号级调用图
2	//!
3	//! 基于 petgraph 构建的符号间调用关系图，
4	//! 支持 BFS 遍历、双向查询（调用者/被调用者）。
5	//!
6	//! # 核心结构
7	//! - [`SymbolNode`] — 图节点，精简的符号信息
8	//! - [`CallGraph`] — petgraph DiGraph 封装，带有 id→NodeIndex 映射
9	//! - [`CallChainNode`] — BFS 遍历结果节点，携带深度与调用类型
10	//!
11	//! # 使用示例
12	//! ```ignore
13	//! use codeconnect_graph::call_graph::CallGraph;
14	//! use codeconnect_index::sled_store::SledStore;
15	//!
16	//! let sled = SledStore::open(path)?;
17	//! let graph = CallGraph::build_from_sled(&sled)?;
18	//! let callers = graph.trace_callers("my_symbol", 3);
19	//! ```
20	
21	use std::collections::{HashMap, VecDeque};
22	
23	use petgraph::graph::{DiGraph, NodeIndex};
24	use petgraph::visit::{Bfs, EdgeRef};
25	use petgraph::Direction;
26	
27	use codeconnect_core::types::{CallEdge, CallType, Symbol, SymbolKind};
28	use codeconnect_core::error::CodeConnectError;
29	use codeconnect_index::sled_store::SledStore;
30	
31	// ============================================================================
32	// 图节点
33	// ============================================================================
34	
35	/// 调用图中的节点，表示一个符号的精简信息
36	///
37	/// 相比完整的 [`Symbol`]，只保留调用图分析所需的关键字段，
38	/// 以降低内存占用并加速图遍历。
39	#[derive(Debug, Clone)]
40	pub struct SymbolNode {
41	    /// 稳定的全局唯一符号 ID
42	    pub symbol_id: String,
43	    /// 符号名称（源代码中的标识符）
44	    pub name: String,
45	    /// 符号种类
46	    pub kind: SymbolKind,
47	    /// 符号所在的源文件路径
48	    pub file_path: String,
49	}
50	
51	impl SymbolNode {
52	    /// 从完整的 [`Symbol`] 创建精简节点
53	    pub fn from_symbol(symbol: &Symbol) -> Self {
54	        Self {
55	            symbol_id: symbol.id.clone(),
56	            name: symbol.name.clone(),
57	            kind: symbol.kind.clone(),
58	            file_path: symbol.location.file_path.clone(),
59	        }
60	    }
61	}
62	
63	// ============================================================================
64	// BFS 遍历结果
65	// ============================================================================
66	
67	/// BFS 调用链中的节点
68	///
69	/// 相比 [`SymbolNode`]，额外携带了 BFS 深度和调用类型信息，
70	/// 便于前端渲染调用链视图。
71	#[derive(Debug, Clone)]
72	pub struct CallChainNode {
73	    /// 符号 ID
74	    pub symbol_id: String,
75	    /// 符号名称
76	    pub name: String,
77	    /// 距离起始符号的 BFS 深度（起始节点深度为 0，直接调用者为 1，以此类推）
78	    pub depth: usize,
79	    /// 调用类型（如 Direct、Virtual、Callback 等）
80	    pub call_type: String,
81	    /// 符号所在的源文件路径
82	    pub file_path: String,
83	}
84	
85	// ============================================================================
86	// 调用图
87	// ============================================================================
88	
89	/// 符号间调用关系图
90	///
91	/// 内部使用 petgraph 的有向图 [`DiGraph`] 存储节点和边，
92	/// 同时维护 `id_to_index` 映射以支持按 stable_id 快速查找节点。
93	///
94	/// 边的方向：caller → callee（调用者指向被调用者）。
95	pub struct CallGraph {
96	    /// 有向图：调用者 → 被调用者
97	    graph: DiGraph<SymbolNode, CallEdge>,
98	    /// 符号 ID → NodeIndex 映射，用于 O(1) 按 ID 查找节点
99	    id_to_index: HashMap<String, NodeIndex>,
100	}
101	
102	impl CallGraph {
103	    /// 创建一个空的调用图
104	    pub fn new() -> Self {
105	        Self {
106	            graph: DiGraph::new(),
107	            id_to_index: HashMap::new(),
108	        }
109	    }
110	
111	    // -----------------------------------------------------------------------
112	    // 节点与边的操作
113	    // -----------------------------------------------------------------------
114	
115	    /// 添加一个节点到图中
116	    ///
117	    /// 如果符号 ID 已经存在，返回已有的 NodeIndex 而不是重复插入。
118	    /// 这样可以在构建图时处理重复符号的情况。
119	    pub fn add_node(&mut self, node: SymbolNode) -> NodeIndex {
120	        if let Some(&idx) = self.id_to_index.get(&node.symbol_id) {
121	            return idx;
122	        }
123	        let idx = self.graph.add_node(node.clone());
124	        self.id_to_index.insert(node.symbol_id, idx);
125	        idx
126	    }
127	
128	    /// 添加一条调用边
129	    ///
130	    /// 调用者和被调用者节点必须已经存在于图中（通过 `add_node` 添加），
131	    /// 否则此方法不会有任何效果。
132	    ///
133	    /// 边的方向：from caller → to callee。
134	    pub fn add_edge(&mut self, caller: &str, callee: &str, edge: CallEdge) {
135	        let from = self.id_to_index.get(caller);
136	        let to = self.id_to_index.get(callee);
137	        if let (Some(&from), Some(&to)) = (from, to) {
138	            self.graph.add_edge(from, to, edge);
139	        }
140	    }
141	
142	    /// 按符号 ID 查找图中的节点引用
143	    ///
144	    /// 返回 `None` 如果该符号不在图中。
145	    pub fn get_node_by_id(&self, symbol_id: &str) -> Option<&SymbolNode> {
146	        self.id_to_index
147	            .get(symbol_id)
148	            .map(|&idx| &self.graph[idx])
149	    }
150	
151	    // -----------------------------------------------------------------------
152	    // BFS 遍历 — 向上查找调用者（谁调用了目标符号）
153	    // -----------------------------------------------------------------------
154	
155	    /// 向上查找调用者链条
156	    ///
157	    /// 从目标符号出发，沿 incoming edges（谁调用了它）方向进行 BFS，
158	    /// 返回所有调用者节点，按发现顺序排列。
159	    ///
160	    /// # 参数
161	    /// - `symbol_id` — 目标符号 ID
162	    /// - `max_depth` — 最大搜索深度（起始节点深度为 0）
163	    ///
164	    /// # 返回
165	    /// 调用链节点列表，不包含起始节点自身。
166	    pub fn trace_callers(
167	        &self,
168	        symbol_id: &str,
169	        max_depth: usize,
170	    ) -> Vec<CallChainNode> {
171	        let start_idx = match self.id_to_index.get(symbol_id) {
172	            Some(&idx) => idx,
173	            None => return Vec::new(),
174	        };
175	
176	        self.trace_bfs(start_idx, max_depth, Direction::Incoming)
177	    }
178	
179	    // -----------------------------------------------------------------------
180	    // BFS 遍历 — 向下查找被调用者（目标符号调用了谁）
181	    // -----------------------------------------------------------------------
182	
183	    /// 向下查找被调用者链条
184	    ///
185	    /// 从目标符号出发，沿 outgoing edges（它调用了谁）方向进行 BFS，
186	    /// 返回所有被调用者节点，按发现顺序排列。
187	    ///
188	    /// # 参数
189	    /// - `symbol_id` — 目标符号 ID
190	    /// - `max_depth` — 最大搜索深度（起始节点深度为 0）
191	    ///
192	    /// # 返回
193	    /// 调用链节点列表，不包含起始节点自身。
194	    pub fn trace_callees(
195	        &self,
196	        symbol_id: &str,
197	        max_depth: usize,
198	    ) -> Vec<CallChainNode> {
199	        let start_idx = match self.id_to_index.get(symbol_id) {
200	            Some(&idx) => idx,
201	            None => return Vec::new(),
202	        };
203	
204	        self.trace_bfs(start_idx, max_depth, Direction::Outgoing)
205	    }
206	
207	    /// BFS 核心遍历逻辑
208	    ///
209	    /// 沿指定方向遍历图，用 visited 集合去重，用 depth_map 追踪深度。
210	    /// 同时维护 parent_map 记录每个节点是从哪个前驱节点发现的，
211	    /// 以便获取连接边的调用类型。
212	    ///
213	    /// - Direction::Incoming → 查找调用者（谁连向我）
214	    /// - Direction::Outgoing → 查找被调用者（我连向谁）
215	    fn trace_bfs(
216	        &self,
217	        start: NodeIndex,
218	        max_depth: usize,
219	        direction: Direction,
220	    ) -> Vec<CallChainNode> {
221	        let mut result: Vec<CallChainNode> = Vec::new();
222	        let mut visited: HashMap<NodeIndex, bool> = HashMap::new();
223	        let mut depth_map: HashMap<NodeIndex, usize> = HashMap::new();
224	        let mut parent_map: HashMap<NodeIndex, NodeIndex> = HashMap::new();
225	        let mut queue: VecDeque<NodeIndex> = VecDeque::new();
226	
227	        // 将起始节点的所有邻居加入队列，记录父节点为 start
228	        let start_depth = 0;
229	        let mut neighbors: Vec<NodeIndex> = self
230	            .graph
231	            .neighbors_directed(start, direction)
232	            .collect();
233	
234	        for neighbor in &neighbors {
235	            depth_map.insert(*neighbor, start_depth + 1);
236	            parent_map.insert(*neighbor, start);
237	            visited.insert(*neighbor, true);
238	            queue.push_back(*neighbor);
239	        }
240	
241	        // BFS 主循环
242	        while let Some(current) = queue.pop_front() {
243	            let depth = *depth_map.get(&current).unwrap_or(&0);
244	
245	            // 收集结果
246	            let node = &self.graph[current];
247	
248	            // 获取从父节点到当前节点的边的调用类型
249	            let call_type = self.get_edge_between(parent_map.get(&current).copied(), current);
250	
251	            result.push(CallChainNode {
252	                symbol_id: node.symbol_id.clone(),
253	                name: node.name.clone(),
254	                depth,
255	                call_type,
256	                file_path: node.file_path.clone(),
257	            });
258	
259	            // 如果已达到最大深度，不再继续展开
260	            if depth >= max_depth {
261	                continue;
262	            }
263	
264	            // 探索当前节点的邻居
265	            neighbors = self
266	                .graph
267	                .neighbors_directed(current, direction)
268	                .collect();
269	
270	            for neighbor in &neighbors {
271	                if visited.contains_key(neighbor) {
272	                    continue;
273	                }
274	                visited.insert(*neighbor, true);
275	                depth_map.insert(*neighbor, depth + 1);
276	                parent_map.insert(*neighbor, current);
277	                queue.push_back(*neighbor);
278	            }
279	        }
280	
281	        result
282	    }
283	
284	    /// 获取从 from_node 到 to_node 的边的调用类型
285	    ///
286	    /// from 是前驱节点（调用者），to 是当前节点（被调用者）。
287	    fn get_edge_between(
288	        &self,
289	        from: Option<NodeIndex>,
290	        to: NodeIndex,
291	    ) -> String {
292	        let from = match from {
293	            Some(f) => f,
294	            None => return "Unknown".to_string(),
295	        };
296	
297	        // 根据方向确定 caller 和 callee
298	        // Incoming：from 通过调用边连接到 to，from 是 caller
299	        // Outgoing：from 通过调用边连接到 to（petgraph neighbors_directed 保证）
300	        let (caller_idx, callee_idx) = (from, to);
301	
302	        // 查找 caller → callee 的边
303	        if let Some(edge) = self.graph.find_edge(caller_idx, callee_idx) {
304	            call_type_to_str(&self.graph[edge].call_type).to_string()
305	        } else {
306	            // 如果精确匹配没找到，尝试反向查找
307	            // (某些情况下边的方向和遍历方向可能不一致)
308	            if let Some(edge) = self.graph.find_edge(callee_idx, caller_idx) {
309	                call_type_to_str(&self.graph[edge].call_type).to_string()
310	            } else {
311	                "Unknown".to_string()
312	            }
313	        }
314	    }
315	
316	    // -----------------------------------------------------------------------
317	    // 从 sled 构建调用图
318	    // -----------------------------------------------------------------------
319	
320	    /// 从 sled 存储中构建完整调用图
321	    ///
322	    /// # 构建过程
323	    /// 1. 扫描 edges: 前缀的所有键，收集所有不重复的符号 ID
324	    /// 2. 对每个符号 ID，从 sled symbols 命名空间读取 [`Symbol`] 并反序列化
325	    /// 3. 将所有符号作为节点加入图
326	    /// 4. 再次遍历所有边，将 [`CallEdge`] 加入图
327	    ///
328	    /// # 参数
329	    /// - `sled` — 已打开的 sled 数据库实例
330	    ///
331	    /// # 错误
332	    /// 在反序列化 Symbol 或 CallEdge 失败时返回错误。
333	    pub fn build_from_sled(sled: &SledStore) -> Result<Self, CodeConnectError> {
334	        let mut call_graph = CallGraph::new();
335	
336	        // ================================================================
337	        // 第一步：扫描所有调用边，收集节点和边的数据
338	        // ================================================================
339	        let edges_prefix = b"edges:";
340	        let mut edge_records: Vec<(String, String, CallEdge)> = Vec::new();
341	        let mut seen_symbols: HashMap<String, bool> = HashMap::new();
342	
343	        for item in sled.scan_prefix(edges_prefix) {
344	            let (key, value) = item?;
345	            let key_str = String::from_utf8_lossy(&key).to_string();
346	
347	            // 键格式：edges:{caller_id}::{callee_id}
348	            // 去掉 "edges:" 前缀后按 "::" 分割
349	            let body = &key_str["edges:".len()..];
350	            let parts: Vec<&str> = body.split("::").collect();
351	            if parts.len() < 2 {
352	                continue; // 跳过格式不符的键
353	            }
354	            let caller_id = parts[0].to_string();
355	            let callee_id = parts[1..].join("::"); // callee_id 可能包含 ::
356	
357	            // 标记出现过的符号
358	            seen_symbols.insert(caller_id.clone(), true);
359	            seen_symbols.insert(callee_id.clone(), true);
360	
361	            // 反序列化 CallEdge
362	            let call_edge: CallEdge = serde_json::from_slice(&value).map_err(|e| {
363	                CodeConnectError::Serialization(e)
364	            })?;
365	
366	            edge_records.push((caller_id, callee_id, call_edge));
367	        }
368	
369	        // ================================================================
370	        // 第二步：为每个出现过的符号创建图节点
371	        // ================================================================
372	        for symbol_id in seen_symbols.keys() {
373	            match sled.get_symbol(symbol_id) {
374	                Ok(Some(data)) => {
375	                    let symbol: Symbol = serde_json::from_slice(&data).map_err(|e| {
376	                        CodeConnectError::Serialization(e)
377	                    })?;
378	                    let node = SymbolNode::from_symbol(&symbol);
379	                    call_graph.add_node(node);
380	                }
381	                Ok(None) => {
382	                    // 符号在 edges 中被引用但不在 symbols 中存储
383	                    // 创建一个占位节点，避免边无法添加
384	                    let placeholder = SymbolNode {
385	                        symbol_id: symbol_id.clone(),
386	                        name: format!("<未知符号:{}>", symbol_id),
387	                        kind: SymbolKind::Unknown(format!("未索引")),
388	                        file_path: String::new(),
389	                    };
390	                    call_graph.add_node(placeholder);
391	                }
392	                Err(_) => {
393	                    // 读取失败也创建占位节点
394	                    let placeholder = SymbolNode {
395	                        symbol_id: symbol_id.clone(),
396	                        name: format!("<未知符号:{}>", symbol_id),
397	                        kind: SymbolKind::Unknown(format!("读取失败")),
398	                        file_path: String::new(),
399	                    };
400	                    call_graph.add_node(placeholder);
401	                }
402	            }
403	        }
404	
405	        // ================================================================
406	        // 第三步：添加所有调用边
407	        // ================================================================
408	        for (caller_id, callee_id, edge) in edge_records {
409	            call_graph.add_edge(&caller_id, &callee_id, edge);
410	        }
411	
412	        Ok(call_graph)
413	    }
414	
415	    // -----------------------------------------------------------------------
416	    // 出入度统计
417	    // -----------------------------------------------------------------------
418	
419	    /// 便捷方法：只用名称添加一条调用边（用于测试和组合构建）
420	    ///
421	    /// 与 `add_edge` 不同，此方法使用 `symbol_id` 作为节点的唯一标识，
422	    /// 并且会自动创建不存在的节点。
423	    pub fn add_edge_raw(&mut self, caller_id: &str, callee_id: &str) {
424	        // 确保节点存在
425	        if !self.id_to_index.contains_key(caller_id) {
426	            let node = SymbolNode {
427	                symbol_id: caller_id.to_string(),
428	                name: caller_id.to_string(),
429	                kind: SymbolKind::Function,
430	                file_path: "test.rs".to_string(),
431	            };
432	            self.add_node(node);
433	        }
434	        if !self.id_to_index.contains_key(callee_id) {
435	            let node = SymbolNode {
436	                symbol_id: callee_id.to_string(),
437	                name: callee_id.to_string(),
438	                kind: SymbolKind::Function,
