461	    /// 获取指定符号的出入度
462	    ///
463	    /// 返回 `(fan_in, fan_out)` 元组：
464	    /// - `fan_in` — 入度（被其他符号调用的次数）
465	    /// - `fan_out` — 出度（调用其他符号的次数）
466	    ///
467	    /// 按 symbol_id 查询（与 `add_node`/`add_edge` 的键一致）。
468	    /// 如果符号不在图中，返回 `(0, 0)`。
469	    pub fn degree(&self, symbol_id: &str) -> (u64, u64) {
470	        let idx = match self.id_to_index.get(symbol_id) {
471	            Some(&i) => i,
472	            None => return (0, 0),
473	        };
474	
475	        let fan_in = self.graph.edges_directed(idx, Direction::Incoming).count() as u64;
476	        let fan_out = self.graph.edges_directed(idx, Direction::Outgoing).count() as u64;
477	        (fan_in, fan_out)
478	    }
