481	    ///
482	    /// 返回所有通过入边连接到该符号的符号 ID 列表。
483	    pub fn get_callers(&self, symbol_id: &str) -> Vec<String> {
484	        let idx = match self.id_to_index.get(symbol_id) {
485	            Some(&i) => i,
486	            None => return Vec::new(),
487	        };
488	
489	        self.graph
490	            .edges_directed(idx, Direction::Incoming)
491	            .map(|e| self.graph[e.source()].symbol_id.clone())
492	            .collect()
493	    }
