496	    ///
497	    /// 返回该符号通过出边调用的所有符号 ID 列表。
498	    pub fn get_callees(&self, symbol_id: &str) -> Vec<String> {
499	        let idx = match self.id_to_index.get(symbol_id) {
500	            Some(&i) => i,
501	            None => return Vec::new(),
502	        };
503	
504	        self.graph
505	            .edges_directed(idx, Direction::Outgoing)
506	            .map(|e| self.graph[e.target()].symbol_id.clone())
507	            .collect()
508	    }
