511	    ///
512	    /// 使用 petgraph 内置 BFS 算法，沿出边方向遍历。
513	    pub fn bfs_reachable(&self, symbol_id: &str) -> Vec<String> {
514	        let start = match self.id_to_index.get(symbol_id) {
515	            Some(&i) => i,
516	            None => return Vec::new(),
517	        };
518	
519	        let mut bfs = Bfs::new(&self.graph, start);
520	        let mut result = Vec::new();
521	        while let Some(node) = bfs.next(&self.graph) {
522	            result.push(self.graph[node].symbol_id.clone());
523	        }
524	        result
525	    }
